import os
import redis
import uuid
from typing import Optional

from fastapi import FastAPI, Depends, HTTPException, status, Security
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials

# --- Configuration ---
# Redis connection details, preferably loaded from environment variables
REDIS_HOST = os.getenv("REDIS_HOST", "localhost")
REDIS_PORT = int(os.getenv("REDIS_PORT", 6379))
REDIS_DB = int(os.getenv("REDIS_DB", 0))

# --- FastAPI Application Instance ---
app = FastAPI(
    title="OAuth2 Bearer Token Validation Service",
    description="A high-performance FastAPI service for validating OAuth 2.0 bearer tokens against a Redis cache.",
    version="1.0.0",
)

# --- Security Scheme Definition ---
# HTTPBearer will extract the token from the "Authorization: Bearer <token>" header
oauth2_scheme = HTTPBearer(description="OAuth 2.0 Bearer token for authentication")

# --- Redis Client Management ---
# Global Redis client instance (will be initialized on startup and closed on shutdown)
redis_client: Optional[redis.Redis] = None

@app.on_event("startup")
async def startup_event():
    """Initializes the Redis client on application startup."""
    global redis_client
    try:
        # decode_responses=True ensures that Redis returns strings instead of bytes
        redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, decode_responses=True)
        # Ping Redis to check connectivity
        redis_client.ping()
        print(f"Connected to Redis at {REDIS_HOST}:{REDIS_PORT}/{REDIS_DB}")

        # --- For Demonstration Purposes: Pre-populate some valid tokens ---
        # In a real system, tokens would be issued by an authentication server
        # and stored in Redis upon issuance.
        redis_client.set("valid_token_user1", "user_id_1", ex=3600) # Token valid for 1 hour
        redis_client.set("valid_token_user2", "user_id_2", ex=3600)
        print("Pre-populated some example tokens in Redis: valid_token_user1, valid_token_user2")
        # --- End Demonstration ---

    except redis.exceptions.ConnectionError as e:
        print(f"ERROR: Could not connect to Redis at {REDIS_HOST}:{REDIS_PORT} - {e}")
        # Depending on your application's requirements, you might want to raise
        # an exception here to prevent the app from starting if Redis is critical.
        # For this example, we'll just log and continue, but endpoints dependent
        # on Redis will fail gracefully.

@app.on_event("shutdown")
async def shutdown_event():
    """Closes the Redis client connection on application shutdown."""
    if redis_client:
        redis_client.close()
        print("Disconnected from Redis.")

# --- Dependency Injection for Redis Client ---
async def get_redis_connection() -> redis.Redis:
    """
    Dependency that provides a Redis client instance.
    Raises an HTTPException if Redis is not available.
    """
    if redis_client is None or not redis_client.ping():
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis service is currently unavailable.",
        )
    return redis_client

# --- Dependency Injection for Token Validation ---
async def get_current_user_id(
    # HTTPBearer returns an HTTPAuthorizationCredentials object if a token is present
    credentials: HTTPAuthorizationCredentials = Security(oauth2_scheme),
    # Inject the Redis connection
    redis_conn: redis.Redis = Depends(get_redis_connection),
) -> str:
    """
    Dependency that validates an OAuth 2.0 bearer token against Redis.
    It extracts the token, checks its presence in Redis, and returns the associated user ID.
    Raises HTTPException 401 Unauthorized if the token is invalid or missing.
    """
    # The actual bearer token string (e.g., "valid_token_user1")
    token = credentials.credentials

    # Check if the token exists as a key in Redis.
    # The value associated with the token is assumed to be the user ID.
    user_id = redis_conn.get(token)

    if not user_id:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired authentication credentials",
            headers={"WWW-Authenticate": "Bearer"}, # Standard header for OAuth2
        )
    return user_id # Return the user ID found in Redis

# --- API Endpoints ---

@app.get("/", tags=["Public"])
async def read_root():
    """Returns a simple greeting for the root path."""
    return {"message": "Welcome to the API! Try /public or /protected."}

@app.get("/public", tags=["Public"])
async def public_endpoint():
    """An endpoint that does not require any authentication."""
    return {"message": "This is a public endpoint. Anyone can access this!"}

@app.get("/protected", tags=["Protected"])
async def protected_endpoint(current_user_id: str = Depends(get_current_user_id)):
    """
    An endpoint that requires a valid OAuth 2.0 bearer token.
    The `get_current_user_id` dependency ensures validation before the endpoint logic executes.
    """
    return {
        "message": f"Welcome, user {current_user_id}! You have accessed a protected resource.",
        "user_id": current_user_id,
        "access_granted": True,
    }

@app.post("/generate-test-token", tags=["Admin/Testing"])
async def generate_test_token(
    requested_user_id: str,
    expiration_seconds: int = 3600, # Default 1 hour
    redis_conn: redis.Redis = Depends(get_redis_connection),
):
    """
    Helper endpoint to generate a new opaque bearer token and store it in Redis.
    This is for testing purposes. In a real application, tokens are issued by
    an authentication server after successful user login.
    """
    new_token = str(uuid.uuid4()) # Generate a unique ID for the token
    redis_conn.set(new_token, requested_user_id, ex=expiration_seconds)
    return {
        "message": "Test token generated successfully. Use this token in 'Authorization: Bearer <token>' header.",
        "token": new_token,
        "user_id_associated": requested_user_id,
        "expires_in_seconds": expiration_seconds,
    }

